INSERT INTO public.option (id, question_id, text, score, tags, "position", created_at, updated_at) VALUES ('887095b8-529d-4705-8904-65ddaf7c89c1', 'ea54230e-abc7-4b71-8d31-02a4d2f44958', 'Every day — cooking is a big part of my life', NULL, '{home-chef}', 3, '2026-04-27 19:30:55.707951+00', '2026-04-27 19:30:55.707951+00');
INSERT INTO public.option (id, question_id, text, score, tags, "position", created_at, updated_at) VALUES ('b80a2856-809a-4468-8c64-f3a3ef907718', '087fe57b-51d1-4c60-9d22-030eef377e28', 'Yes — it''s a serious allergy we have to be really careful about', NULL, '{allergy-tracking,high-alert}', 0, '2026-04-27 19:30:55.707951+00', '2026-04-27 19:30:55.707951+00');
INSERT INTO public.option (id, question_id, text, score, tags, "position", created_at, updated_at) VALUES ('8eb4f966-51fc-4484-97d5-968be8f56275', '087fe57b-51d1-4c60-9d22-030eef377e28', 'More of a sensitivity — we try to avoid certain things', NULL, '{allergy-tracking,sensitivity}', 1, '2026-04-27 19:30:55.707951+00', '2026-04-27 19:30:55.707951+00');
INSERT INTO public.option (id, question_id, text, score, tags, "position", created_at, updated_at) VALUES ('08517d8f-e389-4dde-8613-6fc94c24df8b', '087fe57b-51d1-4c60-9d22-030eef377e28', 'Not really, but I like knowing what''s in my food anyway', NULL, '{label-reader}', 2, '2026-04-27 19:30:55.707951+00', '2026-04-27 19:30:55.707951+00');
INSERT INTO public.option (id, question_id, text, score, tags, "position", created_at, updated_at) VALUES ('c116ff19-ff54-410a-a257-d6dc8d8546b5', '087fe57b-51d1-4c60-9d22-030eef377e28', 'Nope, no restrictions', NULL, '{no-restrictions}', 3, '2026-04-27 19:30:55.707951+00', '2026-04-27 19:30:55.707951+00');
INSERT INTO public.option (id, question_id, text, score, tags, "position", created_at, updated_at) VALUES ('3c8fd4fa-96fb-49e8-ab1b-7e68bbcbe6e1', '87fccd9e-ac4f-484a-ac77-d55aa2e4e4f1', 'I barely glance at them — life''s too short', NULL, '{convenience-first}', 0, '2026-04-27 19:30:55.707951+00', '2026-04-27 19:30:55.707951+00');
INSERT INTO public.option (id, question_id, text, score, tags, "position", created_at, updated_at) VALUES ('a3de7049-e737-40ce-95b0-e0eae81035c4', '87fccd9e-ac4f-484a-ac77-d55aa2e4e4f1', 'I check for a few key things like sugar or sodium', NULL, '{label-reader}', 1, '2026-04-27 19:30:55.707951+00', '2026-04-27 19:30:55.707951+00');
INSERT INTO public.option (id, question_id, text, score, tags, "position", created_at, updated_at) VALUES ('98df609b-beff-438e-a858-b2318bf0b485', '87fccd9e-ac4f-484a-ac77-d55aa2e4e4f1', 'I read them carefully and know what to look for', NULL, '{clean-eating,label-reader}', 2, '2026-04-27 19:30:55.707951+00', '2026-04-27 19:30:55.707951+00');
INSERT INTO public.option (id, question_id, text, score, tags, "position", created_at, updated_at) VALUES ('12dd8e70-ff44-46c9-9830-fec9cd2d3695', '87fccd9e-ac4f-484a-ac77-d55aa2e4e4f1', 'I scrutinize every ingredient — it''s kind of my thing', NULL, '{clean-eating,ingredient-geek}', 3, '2026-04-27 19:30:55.707951+00', '2026-04-27 19:30:55.707951+00');
INSERT INTO public.option (id, question_id, text, score, tags, "position", created_at, updated_at) VALUES ('e39b615d-0bf5-4b4b-af9c-3dde0f0c9b20', 'da8539c6-4cee-4218-9520-25d291947dab', 'Just me', NULL, '{solo-shopper}', 0, '2026-04-27 19:30:55.707951+00', '2026-04-27 19:30:55.707951+00');
INSERT INTO public.option (id, question_id, text, score, tags, "position", created_at, updated_at) VALUES ('666bf98a-012b-4269-9cd6-a533bad01d4e', 'da8539c6-4cee-4218-9520-25d291947dab', 'Me and a partner', NULL, '{couple-household}', 1, '2026-04-27 19:30:55.707951+00', '2026-04-27 19:30:55.707951+00');
INSERT INTO public.option (id, question_id, text, score, tags, "position", created_at, updated_at) VALUES ('f52f8a99-1212-4cd0-b6b8-134e7e2c66ad', 'da8539c6-4cee-4218-9520-25d291947dab', 'Family with kids', NULL, '{family-nutrition,family-household}', 2, '2026-04-27 19:30:55.707951+00', '2026-04-27 19:30:55.707951+00');
INSERT INTO public.option (id, question_id, text, score, tags, "position", created_at, updated_at) VALUES ('e9b98ced-51fc-4780-a53b-59abec480712', 'da8539c6-4cee-4218-9520-25d291947dab', 'Household with other adults (roommates, family)', NULL, '{shared-household}', 3, '2026-04-27 19:30:55.707951+00', '2026-04-27 19:30:55.707951+00');
INSERT INTO public.option (id, question_id, text, score, tags, "position", created_at, updated_at) VALUES ('3a5f0be7-426f-4ccc-975b-32c99e21d37b', 'f2bc1a3b-27c5-4e6b-a1e9-f6dda0a542a0', 'Give me what I know — I''ve got my staples', NULL, '{brand-loyal}', 0, '2026-04-27 19:30:55.707951+00', '2026-04-27 19:30:55.707951+00');
INSERT INTO public.option (id, question_id, text, score, tags, "position", created_at, updated_at) VALUES ('d05a9667-8727-4b38-8376-032f3162e4aa', 'f2bc1a3b-27c5-4e6b-a1e9-f6dda0a542a0', 'I''ll try something new if a friend recommends it', NULL, '{social-discovery}', 1, '2026-04-27 19:30:55.707951+00', '2026-04-27 19:30:55.707951+00');
INSERT INTO public.option (id, question_id, text, score, tags, "position", created_at, updated_at) VALUES ('d81d00e7-dd8e-4936-be66-8012e7e632b5', 'f2bc1a3b-27c5-4e6b-a1e9-f6dda0a542a0', 'I like exploring — always hunting for something better', NULL, '{explorer}', 2, '2026-04-27 19:30:55.707951+00', '2026-04-27 19:30:55.707951+00');
INSERT INTO public.option (id, question_id, text, score, tags, "position", created_at, updated_at) VALUES ('9d89aab9-a954-4bba-ad19-b669c834b429', 'f2bc1a3b-27c5-4e6b-a1e9-f6dda0a542a0', 'I''m basically a product tester, I love finding hidden gems', NULL, '{ingredient-geek,explorer}', 3, '2026-04-27 19:30:55.707951+00', '2026-04-27 19:30:55.707951+00');
INSERT INTO public.option (id, question_id, text, score, tags, "position", created_at, updated_at) VALUES ('7233342f-de27-4167-be6f-0e786b999f78', '5ea3794b-cc7c-4540-a21f-d4e269635c96', 'Flip the dish over to find the brand name', 4, '{}', 0, '2026-04-27 19:31:21.812849+00', '2026-04-27 19:31:21.812849+00');
INSERT INTO public.option (id, question_id, text, score, tags, "position", created_at, updated_at) VALUES ('db9ef050-6d75-457d-89e9-29a5012e8e0c', '5ea3794b-cc7c-4540-a21f-d4e269635c96', 'Ask what''s in it, write nothing down, and forget immediately', 2, '{}', 1, '2026-04-27 19:31:21.812849+00', '2026-04-27 19:31:21.812849+00');
INSERT INTO public.option (id, question_id, text, score, tags, "position", created_at, updated_at) VALUES ('15525ad9-8e36-4107-9134-f4ed2caa714f', '5ea3794b-cc7c-4540-a21f-d4e269635c96', 'Just eat it. Food is food.', 0, '{}', 2, '2026-04-27 19:31:21.812849+00', '2026-04-27 19:31:21.812849+00');
INSERT INTO public.option (id, question_id, text, score, tags, "position", created_at, updated_at) VALUES ('39a2a518-2141-4464-8763-cd7d2645afb7', '5ea3794b-cc7c-4540-a21f-d4e269635c96', 'Photograph it for the ''gram before touching anything', 3, '{}', 3, '2026-04-27 19:31:21.812849+00', '2026-04-27 19:31:21.812849+00');
INSERT INTO public.option (id, question_id, text, score, tags, "position", created_at, updated_at) VALUES ('acbf67bd-a733-4285-a80d-ca50510d05cb', '4af5b2ec-5f89-42c8-9746-f92e7cc85f68', '45 minutes — I read every label twice and do math', 5, '{}', 0, '2026-04-27 19:31:21.812849+00', '2026-04-27 19:31:21.812849+00');
INSERT INTO public.option (id, question_id, text, score, tags, "position", created_at, updated_at) VALUES ('909d4c7c-0d75-4d84-af90-ddc6a90868cc', '4af5b2ec-5f89-42c8-9746-f92e7cc85f68', 'I glance at the picture on the bag and move on', 1, '{}', 1, '2026-04-27 19:31:21.812849+00', '2026-04-27 19:31:21.812849+00');
INSERT INTO public.option (id, question_id, text, score, tags, "position", created_at, updated_at) VALUES ('432edb05-4f1b-4430-b407-16dc540b9270', '4af5b2ec-5f89-42c8-9746-f92e7cc85f68', 'Whatever''s cheapest. Bread is bread.', 0, '{}', 2, '2026-04-27 19:31:21.812849+00', '2026-04-27 19:31:21.812849+00');
INSERT INTO public.option (id, question_id, text, score, tags, "position", created_at, updated_at) VALUES ('58951cf2-c5cf-4f02-8a67-67325aad9c19', '4af5b2ec-5f89-42c8-9746-f92e7cc85f68', 'I only buy bread from one specific local bakery, obviously', 4, '{}', 3, '2026-04-27 19:31:21.812849+00', '2026-04-27 19:31:21.812849+00');
INSERT INTO public.option (id, question_id, text, score, tags, "position", created_at, updated_at) VALUES ('efbc7aa6-5cc0-4073-945a-83ccf2190c25', 'b12f14bb-c07c-4c3f-b57e-610235e71924', 'Ask them to cite their sources', 5, '{}', 0, '2026-04-27 19:31:21.812849+00', '2026-04-27 19:31:21.812849+00');
INSERT INTO public.option (id, question_id, text, score, tags, "position", created_at, updated_at) VALUES ('2d744f52-9f6c-4a29-8f54-64f2c4edf170', 'b12f14bb-c07c-4c3f-b57e-610235e71924', 'Nod, then eat it anyway', 1, '{}', 1, '2026-04-27 19:31:21.812849+00', '2026-04-27 19:31:21.812849+00');
INSERT INTO public.option (id, question_id, text, score, tags, "position", created_at, updated_at) VALUES ('5835c4c8-3d99-45a8-9afc-cf86b3ff48b2', 'b12f14bb-c07c-4c3f-b57e-610235e71924', 'Immediately add it to my mental ''never again'' list', 3, '{}', 2, '2026-04-27 19:31:21.812849+00', '2026-04-27 19:31:21.812849+00');
INSERT INTO public.option (id, question_id, text, score, tags, "position", created_at, updated_at) VALUES ('eb4aa809-1be6-4e4b-97f2-ba12cc986356', 'b12f14bb-c07c-4c3f-b57e-610235e71924', 'What do you mean ''bad for you''? It tastes fine.', 0, '{}', 3, '2026-04-27 19:31:21.812849+00', '2026-04-27 19:31:21.812849+00');
INSERT INTO public.option (id, question_id, text, score, tags, "position", created_at, updated_at) VALUES ('19041d28-552e-4c03-9748-7e284b38a499', 'bf1fa483-353e-44cd-b896-668aafa2397a', '''If you can''t pronounce it, don''t eat it''', 5, '{}', 0, '2026-04-27 19:31:21.812849+00', '2026-04-27 19:31:21.812849+00');
INSERT INTO public.option (id, question_id, text, score, tags, "position", created_at, updated_at) VALUES ('67e3fb1e-cbff-43ff-9aa6-8670e41c0629', 'bf1fa483-353e-44cd-b896-668aafa2397a', '''Everything in moderation'' (but also, yes to everything)', 2, '{}', 1, '2026-04-27 19:31:21.812849+00', '2026-04-27 19:31:21.812849+00');
INSERT INTO public.option (id, question_id, text, score, tags, "position", created_at, updated_at) VALUES ('efe79e39-bdf2-449b-aea5-ee6c2a002158', 'bf1fa483-353e-44cd-b896-668aafa2397a', '''Treat yourself'' — daily, aggressively', 0, '{}', 2, '2026-04-27 19:31:21.812849+00', '2026-04-27 19:31:21.812849+00');
INSERT INTO public.option (id, question_id, text, score, tags, "position", created_at, updated_at) VALUES ('96f99344-86f1-4090-8324-9a8fdfc1f751', 'bf1fa483-353e-44cd-b896-668aafa2397a', '''Food is fuel'' but also food is joy and it''s complicated', 3, '{}', 3, '2026-04-27 19:31:21.812849+00', '2026-04-27 19:31:21.812849+00');
INSERT INTO public.option (id, question_id, text, score, tags, "position", created_at, updated_at) VALUES ('6405692e-3aee-47ea-9223-63c7edfea5bc', '73490f77-21c8-4ebd-be39-5cf7473ad263', 'We''re basically dating. I check in every single day.', 5, '{}', 0, '2026-04-27 19:31:21.812849+00', '2026-04-27 19:31:21.812849+00');
INSERT INTO public.option (id, question_id, text, score, tags, "position", created_at, updated_at) VALUES ('cc7ea4fa-9489-429d-9fd3-5f92f4477a33', '73490f77-21c8-4ebd-be39-5cf7473ad263', 'We''re acquaintances — I know it exists but rarely visit', 2, '{}', 1, '2026-04-27 19:31:21.812849+00', '2026-04-27 19:31:21.812849+00');
INSERT INTO public.option (id, question_id, text, score, tags, "position", created_at, updated_at) VALUES ('a81b097c-87ab-47c2-aa60-5ad94466eac7', '73490f77-21c8-4ebd-be39-5cf7473ad263', 'Strangers. Total strangers.', 0, '{}', 2, '2026-04-27 19:31:21.812849+00', '2026-04-27 19:31:21.812849+00');
INSERT INTO public.option (id, question_id, text, score, tags, "position", created_at, updated_at) VALUES ('56daceae-87ac-4cbe-ad8e-8274597e8622', '73490f77-21c8-4ebd-be39-5cf7473ad263', 'I read it but honestly only understand like three lines', 1, '{}', 3, '2026-04-27 19:31:21.812849+00', '2026-04-27 19:31:21.812849+00');
