INSERT INTO public.result (id, quiz_id, title_text, description, cta_text, cta_url, range_lo, range_hi, created_at, updated_at) VALUES ('0ff46285-40bc-4e44-bb17-97b7baaac32d', '212359b5-4fbd-4eae-94c1-251524608d1d', 'You''re Eating Pretty Clean 🥦', 'Your habits suggest you''re doing a great job avoiding ultra-processed foods. You cook, you read labels, and fast food is a rare treat — keep it up!', 'See How Olive Can Fine-Tune Your Diet', 'https://olive.app/learn', 0, 10, '2026-04-27 19:30:20.60376+00', '2026-04-27 19:30:20.60376+00');
INSERT INTO public.result (id, quiz_id, title_text, description, cta_text, cta_url, range_lo, range_hi, created_at, updated_at) VALUES ('33f44ffc-0355-48a0-8122-e8aa1a50964f', '212359b5-4fbd-4eae-94c1-251524608d1d', 'Not Bad, But There''s Room to Grow 🌿', 'You''ve got solid instincts, but a few ultra-processed habits are sneaking in. Small swaps could make a big difference in how you feel day to day.', 'Explore Olive''s Personalized Tips', 'https://olive.app/start', 11, 22, '2026-04-27 19:30:20.60376+00', '2026-04-27 19:30:20.60376+00');
INSERT INTO public.result (id, quiz_id, title_text, description, cta_text, cta_url, range_lo, range_hi, created_at, updated_at) VALUES ('7655cfaa-604a-469c-a023-1165a6eae418', '212359b5-4fbd-4eae-94c1-251524608d1d', 'Ultra-Processed Foods Are Creeping In 🚧', 'Your diet leans heavily on convenience and packaged foods more often than is ideal. It''s not about perfection — Olive can help you make gradual, sustainable changes.', 'Try Olive and Start Making Changes', 'https://olive.app/start', 23, 34, '2026-04-27 19:30:20.60376+00', '2026-04-27 19:30:20.60376+00');
INSERT INTO public.result (id, quiz_id, title_text, description, cta_text, cta_url, range_lo, range_hi, created_at, updated_at) VALUES ('1f02ab81-dc41-4c73-b1e6-15700016afdb', '212359b5-4fbd-4eae-94c1-251524608d1d', 'Time for a Real Reset 🔴', 'Ultra-processed food is a major part of your daily diet, and it''s likely affecting your energy, gut health, and long-term wellbeing. Olive was built for exactly this moment — let''s change that together.', 'Start Your Olive Reset Today', 'https://olive.app/reset', 35, 48, '2026-04-27 19:30:20.60376+00', '2026-04-27 19:30:20.60376+00');
INSERT INTO public.result (id, quiz_id, title_text, description, cta_text, cta_url, range_lo, range_hi, created_at, updated_at) VALUES ('0b9a3d97-138f-403d-8b86-6a9d5af7b66e', '92f3ce75-5a8e-40d7-b6a8-4a83fcbea49d', 'The Blissfully Unaware', 'Food? Yes. Labels? Never met them. You eat with your heart, your gut, and zero spreadsheets — and honestly, there''s a certain freedom in that. Life''s too short to read the back of a chip bag.', 'Curious what''s actually in your food?', 'https://olive.app/learn', 0, 5, '2026-04-27 19:31:21.812849+00', '2026-04-27 19:31:21.812849+00');
INSERT INTO public.result (id, quiz_id, title_text, description, cta_text, cta_url, range_lo, range_hi, created_at, updated_at) VALUES ('434b404c-32c9-419f-8e38-a97c83779c3a', '92f3ce75-5a8e-40d7-b6a8-4a83fcbea49d', 'The Casual Grazer', 'You care about what you eat — a little. You''ll glance at a label if it''s right there, and you have opinions about food, but you''re not writing a dissertation about it. Balance is your unintentional superpower.', 'Level up your food intuition', 'https://olive.app/start', 6, 11, '2026-04-27 19:31:21.812849+00', '2026-04-27 19:31:21.812849+00');
INSERT INTO public.result (id, quiz_id, title_text, description, cta_text, cta_url, range_lo, range_hi, created_at, updated_at) VALUES ('90d800dc-7ecf-4375-8797-c78321f431a4', '92f3ce75-5a8e-40d7-b6a8-4a83fcbea49d', 'The Conscious Snacker', 'You know enough to be a little stressed about food, but not enough to fully commit to a lifestyle overhaul. You read labels when you remember, you Google ingredients sometimes, and you definitely feel guilty about that last snack.', 'Turn that guilt into knowledge', 'https://olive.app/start', 12, 17, '2026-04-27 19:31:21.812849+00', '2026-04-27 19:31:21.812849+00');
INSERT INTO public.result (id, quiz_id, title_text, description, cta_text, cta_url, range_lo, range_hi, created_at, updated_at) VALUES ('887ca4ab-4ce9-47f1-9888-6d4942ed7648', '92f3ce75-5a8e-40d7-b6a8-4a83fcbea49d', 'The Label Detective', 'Ingredient lists are your love language. You''ve declined food at parties because you couldn''t verify the sourcing. You know what carrageenan is and you have feelings about it. We see you. We are you.', 'Put your skills to work', 'https://olive.app/start', 18, 24, '2026-04-27 19:31:21.812849+00', '2026-04-27 19:31:21.812849+00');
